class Solution:
    def sumOfMultiples(self, n):
        def s(k):
            m = n // k
            return k * m * (m + 1) // 2
        return s(3) + s(5) + s(7) - s(15) - s(21) - s(35) + s(105)

solutions.python:
class Solution:
    def sumOfMultiples(self, n):
        total = 0
        for i in range(1, n + 1):
            if i % 3 == 0 or i % 5 == 0 or i % 7 == 0:
                total += i
        return total

